function parseKpiData(md: string): ParsedKpi | null {
  const result: ParsedKpi = {
    monthLabel: '',
    rows: [],
    annualTarget: '',
    annualActual: '',
    annualRate: '',
    annualForecast: '',
    chances: [],
    actions: [],
  }

  // 当月ラベルを自動判定: "### 当月（X月）着地見込" から取得
  // 月が替わっても最新の「当月」セクションを取得する
  const currentMonth = new Date().getMonth() + 1
  const monthMatch = md.match(/###\s*当月（(.+?)）着地見込 — \d{4}-\d{2}-\d{2}/)
    || md.match(/###\s*当月（(.+?)）着地見込/)
  result.monthLabel = monthMatch ? monthMatch[1] : `${currentMonth}月`

  // "## 着地見込・GAP分析" 以降を対象にする
  const gapSection = md.split('## 着地見込・GAP分析')[1]
  if (!gapSection) return null

  // 最新月セクション（最初の "### 当月" 〜 次の "### 当月（3月）" の間）のみを対象にする
  // 古い月のデータが混入しないよう、最初の当月セクションだけを解析
  const currentMonthSection = gapSection.split(/###\s*当月（[^）]+）着地見込.*?—\s*\d{4}/)[0]
    + (gapSection.match(/###\s*当月（[^）]+）着地見込[^\n]*\n[\s\S]*?(?=###\s*当月（|$)/)?.[0] || '')

  // 列インデックスを動的に検出するヘルパー
  function detectColumnMap(headerCols: string[]): { target: number; actual: number; forecast: number; gap: number; rating: number } {
    const find = (keywords: string[]) => {
      for (const kw of keywords) {
        const idx = headerCols.findIndex(c => c.includes(kw))
        if (idx > 0) return idx
      }
      return -1
    }
    // 10列フォーマット: チャネル|目標(碗)|目標(円)|月中実績|データソース|着地見込(碗)|着地見込(円)|GAP|見込達成率|判定
    // 6列フォーマット:  チャネル|目標|実績|着地見込|GAP|判定
    const targetIdx  = find(['目標(碗)', '目標'])
    const actualIdx  = find(['月中実績', '実績(', '実績'])
    const forecastIdx = find(['着地見込(碗)', '着地見込'])
    const gapIdx     = find(['GAP'])
    const ratingIdx  = find(['判定'])
    return {
      target:   targetIdx   > 0 ? targetIdx   : 1,
      actual:   actualIdx   > 0 ? actualIdx   : 2,
      forecast: forecastIdx > 0 ? forecastIdx : 3,
      gap:      gapIdx      > 0 ? gapIdx      : 4,
      rating:   ratingIdx   > 0 ? ratingIdx   : 5,
    }
  }

  const tableLines = gapSection.split('\n').filter(l => l.startsWith('|') && !l.includes('---'))
  let inKpiTable = false
  let colMap = { target: 1, actual: 2, forecast: 3, gap: 4, rating: 5 }
  let kpiTableDone = false  // 最初のKPIテーブルだけ読む（古い月のデータを除外）

  for (const line of tableLines) {
    if (kpiTableDone) break
    const cols = line.split('|').map(c => c.trim()).filter(Boolean)
    if (cols.length < 6) continue
    if (cols[0] === 'チャネル') {
      // ヘッダー行: 列マップを動的検出
      colMap = detectColumnMap(cols)
      inKpiTable = true
      continue
    }
    if (cols[0] === '優先度' || cols[0] === '領域' || cols[0] === '#') {
      inKpiTable = false
      continue
    }
    // 当月セクション終了の検出（旧月テーブル開始を避ける）
    if (inKpiTable && cols[0] === 'チャネル') {
      kpiTableDone = true
      break
    }
    if (inKpiTable && cols[0] !== '—') {
      const clean = (s: string) => (s || '').replace(/\*\*/g, '').trim()
      result.rows.push({
        channel:  clean(cols[0]),
        target:   clean(cols[colMap.target]),
        actual:   clean(cols[colMap.actual]),
        forecast: clean(cols[colMap.forecast]),
        gap:      clean(cols[colMap.gap]),
        rating:   clean(cols[colMap.rating]),
      })
    }
  }

